SELECT issues.issue_title, issues.status, issue_types.type_name
FROM issues
INNER JOIN issue_types ON issues.type_id = issue_types.type_id;

SELECT project_id, SUM(active_issues) AS TotalActiveIssues
FROM issue_stats
GROUP BY project_id;

SELECT user_name
FROM users
WHERE user_id IN (
  SELECT resolved_by
  FROM issues
  WHERE reopened_count = (
    SELECT MAX(reopened_count)
    FROM issues
  )
);

SELECT issue_title, issue_description
FROM issues
WHERE priority = 'high' AND status = 'active';
